import React from "react";
import { sparePartsData } from "./spare-parts-forecast-graph-hooks";
import GraphContainer from "../graphContainer";
import { ResponsiveBar } from "@nivo/bar";

const SparePartsForecastGraph = () => (
  <GraphContainer title="Spare Parts Forecast">
    <div style={{ width: "100%", height: "100%" }}>
      <ResponsiveBar
        data={sparePartsData}
        keys={["Used Spare Parts", "Predicted Spare Parts"]}
        indexBy="month"
        margin={{ top: 17, right: 30, bottom: 80, left: 70 }}
        groupMode="grouped"
        colors={{ scheme: "nivo" }}
        borderColor={{ from: "color", modifiers: [["darker", 1.6]] }}
        axisTop={null}
        axisRight={null}
        axisBottom={{
          tickSize: 5,
          tickPadding: 5,
          tickRotation: 0,
          legend: "Month (2020)",
          legendPosition: "middle",
          legendOffset: 40,
        }}
        axisLeft={{
          tickSize: 5,
          tickPadding: 5,
          tickRotation: 0,
          legend: "Quantity",
          legendPosition: "middle",
          legendOffset: -40,
        }}
        labelTextColor="black"
        legends={[
          {
            dataFrom: "keys",
            anchor: "bottom-left",
            direction: "row",
            justify: false,
            translateX: -55,
            translateY: 53,
            itemsSpacing: 100,
            itemWidth: 20,
            itemHeight: 20,
            itemDirection: "left-to-right",
            itemOpacity: 0.85,
            symbolSize: 15,
            effects: [
              {
                on: "hover",
                style: {
                  itemOpacity: 1,
                },
              },
            ],
          },
        ]}
        animate={true}
        motionStiffness={90}
        motionDamping={15}
      />
    </div>
  </GraphContainer>
);

export default SparePartsForecastGraph;
